#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char S[N + 1];
        scanf("%s", S);
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (S[i] > S[j]) {
                    char temp = S[i];
                    S[i] = S[j];
                    S[j] = temp;
                }
            }
        }
        printf("%s\n", S);
    }
    return 0;
}

