const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let N = parseInt(input[j * 2]);
            let S = input[j * 2 + 1].split('');
            for (let k = 0; k < N; k++) {
                for (let l = k + 1; l < N; l++) {
                    if (S[k] > S[l]) {
                        let temp = S[k];
                        S[k] = S[l];
                        S[l] = temp;
                    }
                }
            }
            console.log(S.join(''));
        }
    }
});

